package ccxtprediction

import ccxt "github.com/ccxt/ccxt/go/v4"

type Kalshi struct {
	*KalshiCore
	Core          *KalshiCore
	exchangeTyped *ccxt.BaseExchangeTyped
}

func NewKalshi(userConfig map[string]any) *Kalshi {
	p := NewKalshiCore()
	p.Init(userConfig)
	return &Kalshi{
		KalshiCore:    p,
		Core:          p,
		exchangeTyped: ccxt.NewBaseExchangeTyped(&p.BaseExchange),
	}
}
func NewKalshiFromCore(core *KalshiCore) *Kalshi {
	return &Kalshi{
		KalshiCore:    core,
		Core:          core,
		exchangeTyped: ccxt.NewBaseExchangeTyped(&core.BaseExchange),
	}
}

